function ModelInstance:GetBattleNode(diffLvl)
    --关卡ID
    local battleNode = self:GetRawBattleNode(diffLvl)
    if (battleNode == -1) then
        local chapterType = diffLvl or 1
        local battleNum = self:GetBattleNum(diffLvl)
        battleNode = self._battleNumToRefId[chapterType][battleNum]
        return battleNode
    end
    return battleNode
end

