function ModelInstance:GetCurrRoll(diffLvl)
    --获取当前卷
    local mapRef = self:GetWorldMapRef()
    local curChapterId = self:GetChapterId(diffLvl)
    for i, v in pairs(mapRef) do
        local ref = v.ChapterId
        local chapterArr = string.split(ref, ";")
        for j = 1, #chapterArr do
            if (tonumber(chapterArr[j]) == curChapterId and (not diffLvl or v.type == diffLvl)) then
                local refId = v.refId
                return (diffLvl and diffLvl > 1) and v.num or refId
            end
        end
    end
end

function ModelInstance:GetFinallyMissionIndex(missionRefId)
    --获取章的最后关卡数
    local missRef = self:GetInstanceMissionRef()
    for i, v in pairs(missRef) do
        if v.belongChapterId == missionRefId and v.NextinstanceId == -1 then
            return v.num
        end
    end
    return 0
end

function ModelInstance:GetMissionNameWorldByNum(num)
    --获取章节+关卡的名字
    local missRef = self:GetInstanceMissionRef()
    for i, v in pairs(missRef) do
        if v.num == num then
            local chapterId = v.belongChapterId
            local prefix = string.replace(ccClientText(10756), chapterId)
            local name = v.nameWorld
            name = ccLngText(name)
            return prefix .. " " .. name
        end
    end

    if LOG_INFO_ENABLED then
        printInfoNR("GameTable.MainInstanceMissionRef, not find num = " .. (num or "nil"))
    end
    return ""
end

function ModelInstance:GetMissionChapterIdByNum(num, diffLvl)
    --获取章节id
    diffLvl = diffLvl or 1
    local missRef = self:GetInstanceMissionRef()
    for i, v in pairs(missRef) do
        local chapterId = v.belongChapterId
        local chapterData = self:GetInstanceChapterRefByRefId(chapterId)
        if chapterData.type == diffLvl and v.num == num then
            return chapterId
        end
    end

    if LOG_INFO_ENABLED then
        printInfoNR("GameTable.MainInstanceMissionRef, not find num = " .. (num or "nil"))
    end
    return nil
end

