function ModelInstance:IsReliefTroop()
    local cfg = self:GetCurMissionCfg()
    if cfg then
        local reliefTroop = cfg.reliefTroop
        return reliefTroop > 0
    end
    return false
end

function ModelInstance:IsBossShow()
    local cfg = self:GetCurMissionCfg()
    if cfg then
        -- local isBoss = cfg.bossShow
        local isBoss = 0
        return isBoss == 1
    end
    return false
end

function ModelInstance:IsAutoOneKeyUp()
    local autoBattle = self:GetInstancePara("AutoEmbattle") or 0
    local isAutoKeyUp = false
    local missionRef = self:GetMissionCfg(autoBattle)
    if missionRef then
        local autoNum = missionRef.num
        isAutoKeyUp = autoNum >= self._battleNum
    end
    return isAutoKeyUp
end

function ModelInstance:CanEnterBattleNode(battleNode)
    local cfg = self:GetMissionCfg(battleNode)
    if cfg then
        local levelLimit = cfg.openLevelLimit
        local curLevel = gModelPlayer:GetPlayerLv()
        local canEnter = tonumber(curLevel) >= levelLimit
        if not canEnter then
            return false, levelLimit
        else
            return true
        end
    end
    return false, -1
end

function ModelInstance:GetAwardChapterId()
    --获取有奖励没领完的章节ID
    local rewardIds = self:GetRewardIds()
    local _chapterId = self:GetChapterId()
    for i = 1, _chapterId do
        local list = self:GetChapterIdMission(i)
        for k, v in pairs(list) do
            local ref = self:GetInstanceProRewardRefByRefId(k)
            if ref then
                if not rewardIds[k] then
                    return i
                end
            end
        end
    end
    return _chapterId
end

function ModelInstance:GetBGetAwardChapterId(diffLvl)
    --获取能领取的宝箱列表
    local list = {}
    local rewardIds = self:GetRewardIds()--已领取奖励Id集合
    local refList = self:GetInstanceProRewardRef(diffLvl)
    for i, v in pairs(refList) do
        local refId = v.refId
        if not rewardIds[refId] then
            local mission = self:GetMissionCfg(refId)
            local data = {
                ref = v,
                -- specialId = v.specialId,
                specialId = 0,
                refId = v.refId,
                num = mission.num,
                chapter = mission.belongChapterId,
                number = mission.sort
            }
            table.insert(list, data)
        end
    end
    return list
end

function ModelInstance:GetBGetAwardChapterIdJapan()
    --获取能领取的宝箱列表, 只有speicialId 大于0的珍稀奖励才显示
    local list = self:GetBGetAwardChapterId()
    local resultList = {}
    for k, v in ipairs(list) do
        local specialId = v.specialId or 0
        if specialId ~= 0 then
            table.insert(resultList, v)
        end
    end
    return resultList
end

function ModelInstance:GetIsGetRollAwardList(diffLvl)
    --获取没别领取的卷奖励列表
    diffLvl = diffLvl or 1
    local rollList = self:GetMapReceiveList()
    local refList = self:GetWorldMapRefList()
    local list = {}
    for i, v in ipairs(refList) do
        if v.type == diffLvl and not rollList[v.refId] then
            table.insert(list, v)
        end
    end
    return list
end

function ModelInstance:GetIsGetBoxAward()
    local list = self:GetBGetAwardChapterId()
    local chapterId = self:GetChapterId()
    local battleNode = self:GetRawBattleNode()
    for i, v in ipairs(list) do
        local isGet = chapterId >= v.chapter and (battleNode > v.refId or battleNode == -1)
        if isGet then
            return true
        end
    end
    return false
end

function ModelInstance:GetChapterIdMission(chapterID)
    --获取据点数据
    local list = {}
    local missRef = self:GetInstanceMissionRef()
    for k, v in pairs(missRef) do
        if v.belongChapterId == chapterID then
            list[v.refId] = v
        end
    end
    return list
end

function ModelInstance:GetInstanceProRewardRefByRefId(refId)
    return GameTable.MainInstanceProRewardRef[refId]
end

function ModelInstance:GetInstanceProRewardRef(diffLvl)
    local list = {}
    local diffLvlNum = diffLvl or 1
    for i, v in pairs(GameTable.MainInstanceProRewardRef) do
        local mission = gModelInstance:GetMissionCfg(v.refId)
        local chapterCfgData = self:GetInstanceChapterRefByRefId(mission.belongChapterId)
        if (chapterCfgData.type == diffLvlNum) then
            table.insert(list, v)
        end
    end
    table.sort(list, function(a, b)
        return a.sort < b.sort
    end)
    return list
end

function ModelInstance:GetNextProgressCnt(diffLvl)
    --下一进度奖励还差几关
    diffLvl = diffLvl or 1
    local curNode = self:GetRawBattleNode()
    if curNode == -1 then
        local battleNode = self:GetBattleNode(diffLvl)
        local cfg = self:GetNextMissionCfg(battleNode)
        if cfg then
            curNode = cfg.refId
        else
            return -1
        end
    end
    local targetNode = nil
    local rewardRef = self:GetInstanceProRewardRef(diffLvl)
    for k, v in ipairs(rewardRef) do
        local instanceId = v.refId
        if curNode <= instanceId then
            targetNode = instanceId
            break
        end
    end
    if targetNode == nil then
        return -1
    end

    local cnt = 1
    local nextNode = curNode
    while nextNode ~= targetNode do
        local nextMission = self:GetNextMissionCfg(nextNode)
        if not nextMission then
            break
        end
        nextNode = nextMission.refId
        cnt = cnt + 1
    end
    return cnt
end

