function ModelInstance:IsMapOneChapterId(diffLvl)
    --下一章是否下一卷的第一章
    local currRoll = self:GetCurrRoll(diffLvl)
    local ref = self:GetWorldMapRefByRefId(currRoll + 1, diffLvl)
    if (not ref) then
        return 0
    end
    local currChapter = self:GetNextChapterId(diffLvl)
    if (currChapter == -1) then
        return 0
    end
    local chapterArr = string.split(ref.ChapterId, ";")
    if (currChapter == tonumber(chapterArr[1])) then
        return currRoll + 1
    end
    return 0
end

function ModelInstance:GetNextChapterId(diffLvl)
    local chapterId = self:GetChapterId(diffLvl)
    local cfg = self:GetInstanceChapterRefByRefId(chapterId)
    local next = -1
    if cfg then
        next = cfg.NextChapterId
    end
    return next
end

