function ModelInstance:GetCurMissionCfg(diffLvl)
    local battleNode = self:GetBattleNode(diffLvl)
    local cfg = nil
    if battleNode then
        cfg = self:GetMissionCfg(battleNode)
    end
    return cfg
end

function ModelInstance:GetNextMissionCfg(battleNode)
    if not battleNode then
        return nil
    end
    local cfg = self:GetMissionCfg(battleNode)
    if not cfg then
        return nil
    end
    local nextInstanceId = cfg.NextinstanceId
    if nextInstanceId == -1 then
        local chapterId = cfg.belongChapterId
        local chapter = self:GetInstanceChapterRefByRefId(chapterId)
        local nextChapterId = chapter.NextChapterId
        local nextChapter = self:GetInstanceChapterRefByRefId(nextChapterId)
        if not nextChapter then
            return nil
        end
        nextInstanceId = nextChapter.firstInstanceId
    end
    return self:GetMissionCfg(nextInstanceId)
end

