function ModelInstance:GetDropPreData()

    local dataList = {}
    local curCfg = self:GetCurMissionCfg()
    if not curCfg then
        return dataList
    end

    table.insert(dataList, curCfg)

    local curNode = self:GetBattleNode()
    local nextMission = nil
    local showRewardType = 0
    while true do
        nextMission = self:GetNextMissionCfg(curNode)
        if not nextMission then
            break
        end
        showRewardType = nextMission.showRewardType
        if showRewardType == 1 then
            table.insert(dataList, nextMission)
            break
        end
        curNode = nextMission.refId
    end
    return dataList
end

--获取难度 1/3 据点配置
function ModelInstance:GetDiffDropPreData()
    local dataList = {}
    for i = 1, 2 do
        local diffLvl = i == 1 and 1 or 3
        local cfg = self:GetCurMissionCfg(diffLvl)
        if not cfg then
            return dataList
        end
        table.insert(dataList, cfg)
    end
    return dataList
end

