function ModelInstance:ProduceBubble()
    local t = {}
    local totalWeight = 0

    -- bubbleType = bubbleType or 0
    -- if bubbleType == 0 then
    local level = gModelPlayer:GetPlayerLv()
    for k, v in ipairs(GameTable.MainInstanceTalkRef) do
        if level >= v.level then
            table.insert(t, v)
            totalWeight = totalWeight + v.weight
        end
    end
    -- elseif bubbleType == 1 then

    -- for k, v in ipairs(GameTable.MonsterTalkRef) do
    --     table.insert(t, v)
    --     totalWeight = totalWeight + v.weight
    -- end
    -- end
    local rand = math.random(1, totalWeight)
    local cfg = nil
    local randLeft = rand
    for k, v in ipairs(t) do
        local curWeight = v.weight
        if randLeft <= curWeight then
            cfg = v
            break
        else
            randLeft = randLeft - curWeight
        end
    end
    if not cfg then
        return ""
    end

    return ccLngText(cfg.des)
end

