function ModelInstance:GetLittleDropShowData(quality)
    local t = {}
    local rand = nil
    local rate = self._dropshow2T[quality or 0]
    for k, v in ipairs(self._dropshowT) do
        rand = math.random(0, 10000)
        if rand <= v.rate then
            rand = math.random(v.min, v.max)
            if rate then
                rand = rate * rand
            end
            local data = {
                iconPath = v.iconPath,
                itemNum = rand
            }
            table.insert(t, data)
        end
    end
    return t
end

