function ModelInstance:SetPlaceTime(placeTime)

    local oldPlaceTime = self._placeTime or 0
    oldPlaceTime = math.floor(oldPlaceTime)

    local newPlaceTime = placeTime or 0
    newPlaceTime = math.floor(newPlaceTime)

    self._placeTime = placeTime
    FireEvent(EventNames.PLACE_TIME_REFRESH)

    if newPlaceTime == oldPlaceTime then
        printInfoN("place time don't change")
        return
    end
    local popWndId = 30001

    gModelGeneral:RemovePopWndPara(popWndId)
    self._timer:TimerRemoveByKey(self._timeFullPopTimerKey)
    local timePast = GetTimestamp() - self:GetPlaceTime()
    if timePast < 0 then
        timePast = 0
    end
    local timeLeft = GameTable.MainInstanceConfigRef["BoxNoticeTime"] - timePast

    if timeLeft < 0 then
        self:InsertPopWndPara()
    else
        self._timer:TimerCreate(self._timeFullPopTimerKey, function(...)
            self:InsertPopWndPara()
        end, timeLeft, true, 1)
    end

end

