function ModelInstance:GetModaiAniName(isIdle)
    local timeTotal = GetTimestamp() - self:GetPlaceTime()
    if timeTotal < 0 then
        timeTotal = 0
    end
    local aniCfg = self._boxAniCfg[1]

    local index = 1
    for k, v in ipairs(self._boxAniCfg) do
        index = k
        if timeTotal < v.time then
            break
        else
            aniCfg = v
        end
    end
    if isIdle then
        return aniCfg.aniNames[1], index
    else
        local cnt = #aniCfg.aniNames
        local index = math.random(2, cnt)
        return aniCfg.aniNames[index], index
    end
end

