function ModelInstance:TryGotoChallenge(isUICall)
    -- 没有挑战据点的情况：1.达到最大章节 2.需要下一章
    local curDiffLvl = self:GetMainFightLevelOfDifficulty()
    local battleNode = self:GetRawBattleNode(curDiffLvl)
    if battleNode == -1 then
        local chapter = self:GetNextChapterId(curDiffLvl)
        if chapter == -1 then
            GF.ShowMessage(ccClientText(10752))
        else
            local node = self:GetChapterFirstNode(chapter)
            local canEnterBattleNode, limit = self:CanEnterBattleNode(node)
            if not canEnterBattleNode then
                if PRODUCT_G_VER == 1 then
                    if not self:CheckIsShow(17600011) then
                        --ios写死屏蔽
                        local str = string.replace(ccClientText(10781), limit)
                        GF.ShowMessage(str)
                        return
                    end
                end
                if PRODUCT_G_VER == 2 or PRODUCT_G_VER == 3 then
                    return --hw ios写死屏蔽
                end
                GF.OpenWnd("UIUpLvhjgyPop")
                return
            end
            GF.OpenWndWait("UIWaitZC", { hideTime = 1 })
            LxTimer.DelayTimeCall(function()
                GF.OpenWnd("UIGolbMlNew", { true, curDiffLvl })
            end, 0.7)
        end

        return
    else
        -- 等级不足提示
        local canEnterBattleNode, limit = self:CanEnterBattleNode(battleNode)
        if not canEnterBattleNode then
            if PRODUCT_G_VER == 1 then
                if not gModelFunctionOpen:CheckIsShow(17600011) then
                    --ios写死屏蔽
                    local str = string.replace(ccClientText(10781), limit)
                    GF.ShowMessage(str)
                    return
                end
            end
            if PRODUCT_G_VER == 2 or PRODUCT_G_VER == 3 then
                return --hw ios写死屏蔽
            end
            GF.OpenWnd("UIUpLvhjgyPop")
            return
        end
    end
    -- 挑战CD没有冷却提示
    local battleCdEnd = self:GetChallengeCd()
    local isCdEnd = math.floor(battleCdEnd - GetTimestamp()) <= 0
    if not isCdEnd then
        GF.ShowMessage(ccClientText(10751))
        return
    end

    local diffLvl = self:GetMainFightLevelOfDifficulty()

    local callFunc = function()
        if isUICall then
            if (diffLvl > 1) then
                GF.OpenWnd("UIMultiTeamFightPop")
            else
                --self:GotoChallenge()
                gLFightIdleManager:OnChallengeMain()
            end
        else
            if (diffLvl > 1) then
                GF.OpenWnd("UIMultiTeamFightPop")
            else
                gLFightIdleManager:OnChallengeMain()
            end
        end
    end
    if (diffLvl > 1) then
        callFunc()
    else
        self:CheckShowExploreTip(30008, callFunc)
    end
    --local addPoint =  self:GetWinExplorePoint(battleNode)
    -- 探索点超过上限提示
    --local curExplore = gModelExplore:GetCurExplorePoint()
    --local after = curExplore+ self:GetWinExplorePoint(battleNode)
    --if after> gModelExplore:GetMaxExplorePoint() then
    --   gModelGeneral:OpenUIOrdinTips({refId = 30008,func = callFunc})
    --   return
    --end
    ---- 开始走挑战逻辑
    --callFunc()
end

function ModelInstance:GotoChallenge()
    local battleNode = self:GetBattleNode()
    FireEvent(EventNames.TRIGGER_PLOT_BY_MAIN, battleNode, function()
        if self:IsReliefTroop() then
            gLFightIdleManager:OnChallengeUIShow(false)
            gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_MAIN, {})
            return
        end
        if self:IsBossShow() then
            gLFightIdleManager:OnChallengeUIShow(true)
            -- GF.OpenWndUp("UIMinLineMonSow", {mission=battleNode})
            gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_MAIN)
        else
            local heorCombatTips = self:GetInstancePara("heorCombatTips")
            local cfg = self:GetMissionCfg(heorCombatTips)
            local battleNum = self:GetBattleNum()
            local heroCnt = gModelFormation:GetFormationHerosNum(LCombatTypeConst.COMBAT_MAIN)
            local skipBattleFunc = function()
                gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_MAIN)
            end
            local prepareFunc = function()
                gLFightIdleManager:OnChallengeUIShow(false)
                -- gModelBattle:TryGotoMainBattle()
                gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_MAIN)
            end
            if battleNum >= cfg.num and heroCnt > 0 and heroCnt < 5 then
                local para = {
                    refId = 30010,
                    func = prepareFunc,
                    leftFunc = skipBattleFunc,
                    closeFunc = function()
                        gLFightIdleManager:OnChallengeUIShow(false)
                    end
                }
                -- gModelGeneral:OpenUIOrdinTips(para)
                gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_MAIN)
            else
                if prepareFunc then
                    prepareFunc()
                end
            end
        end
    end)
end

