function ModelInstance:QuickHang(srcWnd)

    local cost = self:GetCurQuickCostConfig()
    if cost and cost ~= 0 then
        local itemId, itemNum = cost.itemId, cost.itemNum
        local haveNum = gModelItem:GetNumByRefId(itemId)
        if haveNum < itemNum then
            gModelGeneral:OpenGetWayWnd({ itemId = itemId, srcWnd = srcWnd })
            return
        end
    end

    local func = function()
        self:OnQuickCombatReq()
    end

    self:CheckShowExploreTip(30007, func)


end

function ModelInstance:CheckShowExploreTip(wndId, func)
    local isFunOpen = gModelFunctionOpen:CheckIsOpened(ModelFunctionOpen.EXPLORE_TASK)
    local curPoint = gModelExplore:GetCurExplorePoint()

    --addPoint = addPoint or 1
    local func = func
    ---------------优化需求 #14002------------
    local leftFunc
    if (wndId == 30006 or wndId == 30007 or wndId == 30008) then
        leftFunc = function()
            GF.OpenWnd("UIExre")
        end
    end
    ------------------------------------------
    if curPoint >= gModelExplore:GetMaxExplorePoint() and isFunOpen then
        gModelGeneral:OpenUIOrdinTips({ refId = wndId, func = func, leftFunc = leftFunc })
    else
        func()
    end
end

function ModelInstance:GetQuickTotalTime()
    local timeTotal = self:GetInstancePara("QuickAwardTime") --基础时长
    local isActive = self:GetIsPrivilege() --特权时长
    if isActive then
        --local extraHour = self:GetInstancePara("QuickPriHour")
        local extraHour = gModelActivity:GetQuickExtraHour()
        timeTotal = timeTotal + extraHour * 60
    end
    local extraTime = gModelVip:GetOnHookTime() --vip时长
    timeTotal = timeTotal + extraTime
    return timeTotal
end

function ModelInstance:GetExploreInfoPerMin()
    local exploreInfoId = tonumber(gModelExplore:GetExplorePara("expendItem"))
    local itemNum = 0
    local battleNode = self:GetBattleNode()
    if battleNode then
        local reward = self._timeRewardFixedT[battleNode]
        if reward then
            for k, v in ipairs(reward) do
                if v.itemId == exploreInfoId then
                    itemNum = v.itemNum
                end
            end
        end
    end
    return itemNum
end

function ModelInstance:GetBoxBGet(diffLvl)
    diffLvl = diffLvl or 1
    local battleNum = self:GetBattleNum(diffLvl)
    local battleNode = self:GetRawBattleNode(diffLvl)
    local isGetRewards = self:GetRewardIds()
    for _, v in pairs(GameTable.MainInstanceProRewardRef) do
        local num = self:GetMissionCfg(v.refId).num
