function ModelInstance:GetBoxBGetJapan(showRef)
    local list = self:GetBGetAwardChapterId()
    local maxNum = self:GetMaxBattleNum()
    local battleNum = self:GetBattleNum()
    local num = self:GetBattleNum() - 1
    local battleNode = self:GetRawBattleNode()
    local refId
    if showRef then
        refId = showRef.refId
    end

    local canGetBigReward = false
    if (maxNum == battleNum and battleNode == -1 and #list > 0) then
        if refId then
            for k, v in ipairs(list) do
                if v.refId == refId then
                    canGetBigReward = true
                    break
                end
            end
        end
        return true, canGetBigReward
    end

    local manNode = self:GetNodeByBattleNum(num) or -1
    local manNode1 = self:GetNodeByBattleNum(battleNum)
    local canGet = false
    for i, v in ipairs(list) do
        if (manNode >= v.refId or (manNode1 == v.refId and battleNode == -1)) then
            canGet = true
            if refId and refId == v.refId then
                canGetBigReward = true
                break
            end
        end
    end
    return canGet, canGetBigReward
end

