function ModelInstance:IsShowFormationTipsBubble()
    if not self._bNeedFormationTipsBubble then
        return
    end
    self._bNeedFormationTipsBubble = false
    local growTips = self:GetInstancePara("GrowTips") or 0
    local growRef = self:GetMissionCfg(growTips)
    if not growRef then
        return false
    end

    local curMission = self:GetCurMissionCfg()
    if not curMission then
        return false
    end

    if curMission.num > growRef.num then
        return false
    end

    local combatType = LCombatTypeConst.COMBAT_MAIN
    local formation = gModelFormation:GetFormation(combatType)
    local formationType = 1
    -- local artifact = 0【G公共支持】删除神器功能相关数据
    local power = 0
    if formation then
        -- artifact = formation.artifactId or 0【G公共支持】删除神器功能相关数据
        formationType = formation.formationType
        local grids = formation.grids or {}
        for k, v in ipairs(grids) do
            local heroId = v.id
            local heroData = gModelHero:GetHeroById(heroId)
            if heroData then
                power = (heroData:GetPower() or 0) + power
            end
        end
    end
    if formationType == 0 then
        formationType = 1
    end

    local indexToIdList = gModelFormation:GetOneKeyUpFormation(LCombatTypeConst.COMBAT_MAIN, formationType)
    local newPower = 0
    for k, v in pairs(indexToIdList) do
        local heroId = v
        local heroData = gModelHero:GetHeroById(heroId)
        if heroData then
            newPower = (heroData:GetPower() or 0) + newPower
        end
    end

    if power >= newPower then
        return false
    end

    return true
end

