function ModelInstance:ShowKillMonWnd()
    if self._hasKillMonShow then
        return
    end
    self._hasKillMonShow = true
    local isInGuide = gModelGuide:IsInGuide()
    if isInGuide then
        return
    end
    local playerLv = gModelPlayer and gModelPlayer:GetPlayerLv() or 0
    local limitLv = self:GetInstancePara("MonKillShowLv")
    if playerLv < limitLv then
        return
    end
    local monKillShowTime = self:GetInstancePara(" MonKillShowTime") or 0
    local time = GetTimestamp() or 0
    local lastTime = gModelPlayer and gModelPlayer:GetLastLogoutTime() or 0
    lastTime = tonumber(lastTime)
    lastTime = math.floor(lastTime / 1000)
    local distime = time - lastTime
    if distime <= monKillShowTime * 60 then
        return
    end
    if self._killMonsterNotifyCount > 0 then
        local argList = { killNum = self._killMonsterNotifyCount }
        gModelGeneral:OpenOnHookPopWnd({ wnd = "UIGjKillMon", para = argList, layer = LGameUI.UI_SORTLAYER_UIBOTTOM })
    end
end

