function ModelInstance:GetImproveDataByDiffLvl(diffLvl)
    local curNode = self:GetBattleNode(diffLvl)
    local itemList = self:GetMissionTimeRewardFix(curNode)
    local battleNum = self:GetBattleNum(diffLvl)
    local lastNode = self:GetNodeByBattleNum(battleNum - 1, diffLvl)
    local oldItemList = self:GetMissionTimeRewardFix(lastNode)
    local itemMap = {}
    for k, v in ipairs(itemList) do
        itemMap[v.itemId] = v
    end
    local dataList = {}
    if not oldItemList then
        return
    end
    for k, v in ipairs(oldItemList) do
        local itemId = v.itemId
        local newItemData = itemMap[itemId]
        local oldItemNum = v.itemNum
        local newItemNum = newItemData and newItemData.itemNum or 0
        local data = {
            itemId = itemId,
            itemType = v.itemType,
            oldItemNum = oldItemNum,
            newItemNum = newItemNum,
        }
        table.insert(dataList, data)
    end
    return dataList
end

