function ModelInstance:GenerateNewShowMonRefId()
    local monSeqLen = self._showMonSeqLen
    local monSeqList = self._showMonSeqList
    if monSeqLen <= 0 then
        monSeqLen = #self._showMonsList
        monSeqList = LUtil.GenerateSeqList(monSeqLen)
        self._showMonSeqList = monSeqList
    end

    local rand = LUtil.RandInteger(monSeqLen)
    local showMonRefId = monSeqList[rand]
    table.remove(monSeqList, rand)
    local showRef = self._showMonsList[showMonRefId]
    local refId = showRef and showRef.monster
    self._curShowMonRefId = refId
    monSeqLen = monSeqLen - 1
    self._showMonSeqLen = monSeqLen

    return refId
end

function ModelInstance:AddClientKillMon(cnt)
    local nowCnt = self._clientKillMon or 0
    self._clientKillMon = nowCnt + cnt

    local time = Time.unscaledTime
    if not self._lastRecordMonKillTime then
        self._lastRecordMonKillTime = time + self._monKillRecordCd
        return
    end
    if time >= self._lastRecordMonKillTime then
        self._lastRecordMonKillTime = time + self._monKillRecordCd

        local cnt = self._clientKillMon or 0
        if cnt > 0 then
            self:OnInstanceKillTimeReq(cnt)
            self._clientKillMon = 0
        end
    end
end

function ModelInstance:OnInstanceKillTimeReq(cnt)
    cnt = cnt or 0
    local pb = LProtoHelper.CreateProto(LProtoIds.InstanceKillTimeReq)
    pb.killMonsterCount = cnt
    SendMessage(pb, LProtoIds.InstanceKillTimeReq)
end

function ModelInstance:OnInstanceKillTimeResp(pb, ret)
    if ret ~= 0 then
        return
    end
    local killMonsterCount = tonumber(pb.killMonsterCount)
    local addCount = tonumber(pb.addCount)
    self._killMonsterCount = killMonsterCount

    if not self._killMonsterNotifyCount or self._killMonsterNotifyCount <= 0 then
        self._killMonsterNotifyCount = addCount
    end
end
