---配置预处理
function ModelInstance:ParseConfig()
    self._missionNum2RefId = {}
    self._monsterIdToRefId = {}
    self._timeRewardFixedT = {}
    self._showRewardT = {}
    self._lastChapterNodeT = {}
    self._battleNumToRefId = {}
    self._maxBattleNum = {}  --最大关卡数
    self._oldBattleByChapter = {}
    local missRef = self:GetInstanceMissionRef()
    for k, v in pairs(missRef) do
        local chapterData = self:GetInstanceChapterRefByRefId(v.belongChapterId)
        local chapterBattles = self._oldBattleByChapter[v.belongChapterId]
        if (not chapterBattles) then
            chapterBattles = {}
            self._oldBattleByChapter[v.belongChapterId] = chapterBattles
        end
        chapterBattles[v.NextinstanceId] = v.refId
        local timeRewardFixed = v.timeRewardFixed
        local t = self:ParseItem3(timeRewardFixed)
        self._timeRewardFixedT[k] = t
        local chapterId = v.belongChapterId
        local battleNode = v.refId
        if v.NextinstanceId == -1 then
            self._lastChapterNodeT[chapterId] = battleNode
        end
        local battleNum = v.num
        self._battleNumToRefId[chapterData.type] = self._battleNumToRefId[chapterData.type] or {}
        self._battleNumToRefId[chapterData.type][battleNum] = battleNode
        self._maxBattleNum[chapterData.type] = self._maxBattleNum[chapterData.type] or 0
        if (self._maxBattleNum[chapterData.type] < battleNum) then
            self._maxBattleNum[chapterData.type] = battleNum
        end
        local showReward = v.showReward
        self._showRewardT[k] = LxDataHelper.ParseItem(showReward)

        self._missionNum2RefId[battleNum] = k

        local monster = v.monster
        self._monsterIdToRefId[monster] = battleNode
    end

    local boxAniCfg = GameTable.MainInstanceConfigRef["BoxRes2"]
    self._boxAniCfg = self:ParseModaiAni(boxAniCfg)

    local dropShow = GameTable.MainInstanceConfigRef["Dropshow"]
    self._dropshowT = self:ParseDropShow(dropShow)
    self._dropshow2T = LxDataHelper.ParseIntKVList_Semicolon(GameTable.MainInstanceConfigRef["Dropshow2"] or "")
    self._dropScale = GameTable.MainInstanceConfigRef["DropScale"] or 1

    self._dropShowMon = self:ParseDropShow(GameTable.MainInstanceConfigRef["DropshowMon"])

    local boxEffect = GameTable.MainInstanceConfigRef["BoxRes"]
    self._boxEffect = self:ParseBoxEffect(boxEffect)

    self._monKillRecordCd = (GameTable.MainInstanceConfigRef["MonKillRecordCd"] or 0) * 60

    local showMonsList = {}
    -- for k, v in pairs(GameTable.InstanceMonShowRef) do
    --     table.insert(showMonsList, v)
    -- end
    self._showMonsList = showMonsList

    self._showMonSeqLen = 0
    self._showMonSeqList = {}
    self._curShowMonRefId = 0
end

function ModelInstance:GetInstanceFunctionRef()
    local list = {}
    for i, v in pairs(GameTable.MainInstanceFunctionRef) do
        table.insert(list, v)
    end
    table.sort(list, function(a, b)
        return a.sort < b.sort
    end)
    return list
end

function ModelInstance:ParseItem3(str)
    local strList = string.split(str, ',')
    local itemList = {}
    for k, v in pairs(strList) do
        local s, e, cap1, cap2, cap3 = string.find(v, "(%d+)=(%d+)=(%d+)")
        if not cap1 or not cap2 or not cap3 then
            printInfoN("ModelInstance:ParseItem3, wrong cfg " .. str)
            break
        end
        local t = {
            itemType = tonumber(cap1),
            itemId = tonumber(cap2),
            itemNum = tonumber(cap3),
        }
        table.insert(itemList, t)
    end
    return itemList
end

function ModelInstance:ParseIdList(str)
    local t = {}
    local strs = string.split(str, ";")
    for k, v in ipairs(strs) do
        local value = math.floor(tonumber(v))
        table.insert(t, value)
    end
    return t
end

function ModelInstance:ParseCostList(str)
    local strList = string.split(str, ';')
    local itemList = {}
    for k, v in pairs(strList) do
        local s, e, cap1, cap2, cap3 = string.find(v, "(%d+)=(%d+)=(%d+)")
        if not cap1 or not cap2 or not cap3 then
            printInfoN("ModelInstance:ParseCostList, wrong cfg " .. str)
            break
        end
        local t = {
            itemType = tonumber(cap1),
            itemId = tonumber(cap2),
            itemNum = tonumber(cap3),
        }
        table.insert(itemList, t)
    end
    return itemList
end

function ModelInstance:ParseModaiAni(str)
    local aniCfg = {}
    local strs = string.split(str, ';')
    for k, v in pairs(strs) do
        local tempStrs = string.split(v, '=')
        if #tempStrs < 2 then
            printInfoN("ModelInstance:ParseModaiAni, wrong cfg " .. str)
            break
        end
        local time = tonumber(tempStrs[1])
        local aniStrs = string.split(tempStrs[2], ':')
        local t = {
            time = time,
            aniNames = aniStrs,
        }
        table.insert(aniCfg, t)
    end
    table.sort(aniCfg, function(a, b)
        return a.time < b.time
    end)
    return aniCfg
end

function ModelInstance:ParseDropShow(str)
    local t = {}
    local strs = string.split(str, ';')
    for k, v in ipairs(strs) do
        local s, e, cap1, cap2, cap3, cap4 = string.find(v, "([%w_]+)=(%d*%.*%d*)=(%d+):(%d+)")
        if not cap1 or not cap2 or not cap3 or not cap4 then
            printInfoN("ModelInstance:ParseDropShow, wrong cfg " .. str .. " index=" .. k .. " value=" .. v)
            break
        end

        local data = {
            iconPath = cap1,
            rate = (tonumber(cap2) or 0) * 10000,
            min = tonumber(cap3),
            max = tonumber(cap4),
        }
        table.insert(t, data)
    end
    return t
end

function ModelInstance:ParseBoxEffect(str)
    local t = {}
    local strs = string.split(str, ';')
    for k, v in ipairs(strs) do
        local s, e, cap1, cap2 = string.find(v, "(%d+)=([%w_]+)")
        if not cap1 or not cap2 then
            printInfoN("ModelInstance:ParseBoxEffect, wrong cfg " .. str)
            break
        end

        local data = {
            time = tonumber(cap1),
            effectName = cap2,
        }
        table.insert(t, data)
    end
    return t
end

