function ModelInstance:CheckShowTip(diffLvl)
    local battleNode = self:GetRawBattleNode(diffLvl)
    local curBattleNode = battleNode
    if battleNode == -1 then
        local chapter = self:GetNextChapterId(diffLvl)
        if chapter ~= -1 then
            local node = self:GetChapterFirstNode(chapter)
            curBattleNode = node
        end
    end

    local showTip = false
    local canEnterBattleNode = false
    local limit = 0
    if curBattleNode ~= -1 then
        canEnterBattleNode, limit = self:CanEnterBattleNode(curBattleNode)
        showTip = not canEnterBattleNode
    end
    return showTip, limit or 0
end

function ModelInstance:IsBattleNodePass(battleNode)
    local ref = self:GetMissionCfg(battleNode)
    if not ref then
        printInfoN(string.format("not instance cfg %s", battleNode))
        return false
    end
    local battleNum = ref.num
    local curBattleNum = self:GetPassedBattleNum()
    return curBattleNum >= battleNum
end

function ModelInstance:GetPassedBattleNum(diffLvl)
    local battleNum = nil
    diffLvl = diffLvl or 1
    local curBattleNum = self:GetRawBattleNode(diffLvl)
    if curBattleNum ~= -1 then
        battleNum = self:GetBattleNum(diffLvl) - 1
    else
        battleNum = self:GetBattleNum(diffLvl)
    end

    return battleNum
end

