--勇者/英雄难度 跳过战斗/布阵
function ModelInstance:SetMainFightDiffLvlSkip(diffLvl, value, skipType, showSkipTips)
    if (value) then
        local paraKeyIndex = diffLvl - 1
        local skipTypeKey = skipType == 1 and "emBattle" or "jumpBattle"
        local limitMissionId = self:GetInstancePara(skipTypeKey .. paraKeyIndex)
        local missCfg = self:GetMissionCfg(limitMissionId)
        local limitChapterId = missCfg.belongChapterId
        local limitChapterData = self:GetInstanceChapterRefByRefId(limitChapterId)
        local battleNode = self:GetLastBattleNode(limitChapterData.type)
        local canSkip = (battleNode and battleNode >= limitMissionId)
        if (not canSkip) then
            local name = missCfg.nameWorld
            if (showSkipTips) then
                GF.ShowMessage(string.replace(ccClientText(16344), missCfg.num, ccLngText(name)))
            end
            return false
        end
    end
    if (diffLvl == 2) then
        if (skipType == 1) then
            LPlayerPrefs.SetMainFightBraveSkipEmbattle(value)
        else
            LPlayerPrefs.SetMainFightBraveSkipBattle(value)
        end
    elseif (diffLvl == 3) then
        if (skipType == 1) then
            LPlayerPrefs.SetMainFightHeroSkipEmbattle(value)
        else
            LPlayerPrefs.SetMainFightHeroSkipBattle(value)
        end
    end
    return true
end

function ModelInstance:GetMainFightDiffLvlSkip(diffLvl, skipType)
    if (diffLvl == 2) then
        if (skipType == 1) then
            return toboolean(LPlayerPrefs.mainFightBraveSkipEmbattle)
        else
            return toboolean(LPlayerPrefs.mainFightBraveSkipBattle)
        end
    elseif (diffLvl == 3) then
        if (skipType == 1) then
            return toboolean(LPlayerPrefs.mainFightHeroSkipEmbattle)
        else
            return toboolean(LPlayerPrefs.mainFightHeroSkipBattle)
        end
    end
end
