function ModelInstance:SetMainFightLevelOfDifficulty(value)
    local funcIsOpen = self:CheckDiffLvlFuncIsOpen(value)
    if (value == 1 or funcIsOpen) then
        LPlayerPrefs.SetMainFightLevelOfDifficulty(value)
    end
end
function ModelInstance:GetMainFightLevelOfDifficulty()
    --local a = tonumber(LPlayerPrefs.mainFightDifficultyLvl)
    return tonumber(LPlayerPrefs.mainFightDifficultyLvl)
end
