function ModelInstance:CheckDiffLvlFuncIsOpen(lvl)
    if (lvl == 1) then
        return true
    end
    local funcId = lvl == 2 and 10203000 or 10204000
    local openData = gModelFunctionOpen:CheckIsOpened(funcId)
    return openData
end
