function ModelInstance:ShowDiffLvlOpenTips(lvl)
    local funcId = lvl == 2 and 10203000 or 10204000
    local openTips = gModelFunctionOpen:GetOpenTips(funcId)
    GF.ShowMessage(openTips)
end

function ModelInstance:IsMainLineCombat(combatType)
    ---是否是主线的战斗类型
    if not combatType then
        return false
    end
    if combatType == LCombatTypeConst.COMBAT_MAIN then
        return true
    elseif combatType == LCombatTypeConst.COMBAT_TYPE_30 then
        return true
    elseif combatType == LCombatTypeConst.COMBAT_TYPE_31 then
        return true
    end
    return false
end
function ModelInstance:GetBattlePreMonsterArrByCombatType(combatType)
    --获取勇者和英雄模式怪物组
    local diffLvlData = nil
    if combatType == LCombatTypeConst.COMBAT_TYPE_30 then
        diffLvlData = gModelInstance:GetBraveDiffLvlData()
    elseif combatType == LCombatTypeConst.COMBAT_TYPE_31 then
        diffLvlData = gModelInstance:GetHeroDiffLvlData()
    end
    if not diffLvlData then
        return {}
    end
    local battleNode = diffLvlData.battleNode
    local ref = gModelInstance:GetMissionCfg(battleNode)
    local monsterArr = LxDataHelper.ParseNumber_Sign(ref.monsterMore, ',')
    return monsterArr
end
