--停止计时器之类的
function ModelInstance:OnModelClear()
    local timer = self._timer
    if (timer) then
        timer:Destroy()
        self.timer = nil
    end
end

function ModelInstance:CanQuickGetPassReward(includeNode)
    local dataList = self:GetBGetAwardChapterId()
    local canGetNum = 0
    for i, v in ipairs(dataList) do
        local canGet = self:IsBattleNodePass(v.refId)
        if canGet or includeNode[v.refId] then
            canGetNum = canGetNum + 1
        end
    end
    local canQuick = canGetNum > 0

    return canQuick

end

function ModelInstance:CheckCombatTypeIsDiffMainFight(combatType)
    return combatType == LCombatTypeConst.COMBAT_TYPE_30 or combatType == LCombatTypeConst.COMBAT_TYPE_31
end

function ModelInstance:GetMainLineRewardRPByDiffLvl(diffLvl)
    local index = diffLvl or 1
    local funcOpen = gModelInstance:CheckDiffLvlFuncIsOpen(index)
    local isShowRP = false
    if (funcOpen) then
        local rewardList = gModelInstance:GetInstanceProRewardRefByDeffLvl(index)
        local rewardIds = gModelInstance:GetRewardIds()
        local mapReceiveList = gModelInstance:GetMapReceiveList()
        local worldMapRef = gModelInstance:GetWorldMapRefList()
        local currRoll = gModelInstance:GetCurrRoll(index)
        local chapterId = gModelInstance:GetChapterId(index)
        local isShowOneKey = false            --是否可以一键领取
        local battleNode = gModelInstance:GetRawBattleNode(index)
        local _passedBattleNum = gModelInstance:GetPassedBattleNum(index)
        local showMapRef = gModelInstance:GetShowMapRefDataByDiffLvl(worldMapRef, mapReceiveList, index)
        for i, v in ipairs(rewardList) do
            local refId = v.refId
            local data = ModelInstance:GetListItemData(v, refId)
            if not isShowOneKey and _passedBattleNum >= data.num and not rewardIds[refId] then
                isShowOneKey = true
            end
        end
        local isRollReach = currRoll > showMapRef.num
        if currRoll == showMapRef.num then
            local mapRef = gModelInstance:GetWorldMapRefByRefId(currRoll)
            local ChapterIdArr = string.split(mapRef.ChapterId, ";")
            local maxChapter = ChapterIdArr[#ChapterIdArr]
            maxChapter = tonumber(maxChapter)
            if chapterId == maxChapter then
                isRollReach = battleNode == -1
            end
        end
        local mapReceiveTime = gModelInstance:GetMapReceiveTime(index)
        mapReceiveTime = tonumber(mapReceiveTime) / 1000
        local curTime = GetTimestamp()
        local dayTime = LUtil.GetNextDayTimes(mapReceiveTime > 0 and mapReceiveTime or nil, showMapRef.intervalTime)
        local isTimeReach = mapReceiveTime <= 0 or curTime >= dayTime
        local isGetMap = isRollReach and isTimeReach
        local isGetReward = not mapReceiveList[showMapRef.refId] and isGetMap
        isShowRP = isShowOneKey or isGetReward
    end
    return isShowRP
end

function ModelInstance:GetInstanceProRewardRefByDeffLvl(diffLvl)
    local proRewardRef = gModelInstance:GetInstanceProRewardRef(diffLvl)
    local rewardList = {}
    for i, v in pairs(proRewardRef) do
        local mission = gModelInstance:GetMissionCfg(v.refId)
        local chapterCfgData = gModelInstance:GetInstanceChapterRefByRefId(mission.belongChapterId)
        if (chapterCfgData.type == diffLvl) then
            table.insert(rewardList, v)
        end
    end
    return rewardList
end

function ModelInstance:GetShowMapRefDataByDiffLvl(worldMapRef, mapReceiveList, diffLvl)
    local tmpShowMapRes
    local tmpShowMapRes2
    for i, v in ipairs(worldMapRef) do
        if (v.type == diffLvl) then
            tmpShowMapRes = v
        end
        if not mapReceiveList[v.refId] and v.type == diffLvl then
            tmpShowMapRes2 = v
            break
        end
    end
    return tmpShowMapRes2 or tmpShowMapRes
end

function ModelInstance:GetListItemData(itemdata, refId)
    local missionRef = gModelInstance:GetMissionCfg(refId)
    local data = {
        refId = refId,
        num = missionRef.num,
        chapter = missionRef.belongChapterId,
        number = missionRef.sort,
        reward = itemdata.reward,
    }
    return data
end

function ModelInstance:GetMissionRefIdByNum(num)
    return self._missionNum2RefId[num]
end

function ModelInstance:GetMissionRefByNum(num)
    local refId = self:GetMissionRefIdByNum(num)
    if not refId then
        return
    end
    return self:GetMissionCfg(refId)
end

function ModelInstance:GetHeroAttSpeedUp()
    local info = string.split(GameTable.MainInstanceConfigRef["HeroAttSpeedUp"], ",")
    local curSpeed = 1
    for _, v in ipairs(info) do
        local data = string.split(v, "=")
        local speed = 0
        local needUpdate = true
        if data[2] then
            local lvl = tonumber(data[2])
            local playerLvl = gModelPlayer:GetPlayerLv()
            if lvl ~= 0 and playerLvl >= lvl then
                speed = tonumber(data[1])
                needUpdate = false
            end
        end
        if data[3] and needUpdate then
            local vip = tonumber(data[3])
            local playerVip = gModelPlayer:GetVipLevel()
            if vip ~= 0 and playerVip >= vip then
                speed = tonumber(data[1])
                needUpdate = false
            end
        end
        if data[5] and needUpdate then
            if tonumber(data[5]) ~= 0 and gModelFunctionOpen:CheckBattleNum(tonumber(data[5])) then
                speed = tonumber(data[1])
            end
        end
        if speed > curSpeed then
            curSpeed = speed
        end
    end
    return curSpeed
end

return ModelInstance